# include <iostream># include <vector>using namespace std; int main(void){	ios::sync_with_stdio(false);	cin.tie(NULL);	cout.tie(NULL);		int d, sumTime;	cin >> d >> sumTime;	int minSum = 0, maxSum = 0; 	vector<int> minTimes(d, 0), maxTimes(d, 0); 	for (int i=0; i<d; i++){		cin >> minTimes[i] >> maxTimes[i];		minSum += minTimes[i];		maxSum += maxTimes[i];	} 	if (sumTime >= minSum && sumTime <= maxSum){		cout << "YES\n"; 		int left = sumTime - minSum; 		for (int i=0; i<d; i++){			int& maxTime = maxTimes[i], minTime = minTimes[i];			if (i)				cout << ' ';			if (left > maxTime - minTime){				cout << maxTime;				left -= maxTime - minTime;			}			else {				cout << minTime + left;				left = 0;			}		}	}	else {		cout << "NO\n";	}}